  private void OK_button_actionPerformed(
      java.awt.event.ActionEvent evt) { // GEN-FIRST:event_OK_button_actionPerformed
    // TODO add your handling code here:
    boolean doorgaan;

    ////// obs format (FM13 or 101 or AWS) /////
    //
    if (jRadioButton1.isSelected() == true) // FM13
    {
      main.obs_format = main.FORMAT_FM13;
      doorgaan = true;
    } else if (jRadioButton2.isSelected() == true) // 101 format
    {
      main.obs_format = main.FORMAT_101;
      doorgaan = true;
    } else if (jRadioButton7.isSelected() == true) // AWS format
    {
      main.obs_format = main.FORMAT_AWS; // NB only for EUCAWS (OMC-140 must be 101 or FM13)
      main.eucaws_uploads_method = "";
      doorgaan = true;
    } else // obs format unknown
    {
      main.obs_format = "";
      doorgaan = false;

      String info = "Obs format unknown";
      JOptionPane.showMessageDialog(
          null, info, main.APPLICATION_NAME + " error", JOptionPane.WARNING_MESSAGE);
    } // else (obs format unknown)

    // obs format EUCAWS-AWS, so we have to check upload method too (eucaws or turbowin)
    //
    if ((doorgaan == true) && (main.obs_format.equals(main.FORMAT_AWS))) {
      /////// EUCAWS uploads (EUCAWS or TurboWin+)
      //
      if (jRadioButton3.isSelected() == true) // uploads via EUCAWS device (iridium modem)
      {
        main.eucaws_uploads_method = main.UPLOADS_VIA_EUCAWS;
        doorgaan = true;
      } else if (jRadioButton4.isSelected() == true) // uploads via TurboWin+ (ship's internet)
      {
        main.eucaws_uploads_method = main.UPLOADS_VIA_TURBOWIN;
        doorgaan = true;
      } else {
        main.eucaws_uploads_method = "";
        doorgaan = false;
      } // else

      // obs format = AWS and upload method unknown
      //
      if (doorgaan == false) {
        String info = "EUCAWS upload method unknown";
        JOptionPane.showMessageDialog(
            null, info, main.APPLICATION_NAME + " error", JOptionPane.WARNING_MESSAGE);
      }

      // check if OBS_ID must be added to SMD input
      //
      if (doorgaan == true) {
        if (jCheckBox1.isSelected()) {
          // add obs id (observer initials) to SMD input
          main.eucaws_obs_id = true;
        } else {
          main.eucaws_obs_id = false;
        }
      }
    } // if ( (doorgaan == true) && (main.obs_format.equals(main.FORMAT_AWS)) )

    if ((doorgaan == true) && (main.obs_format.equals(main.FORMAT_101))
        || ((main.obs_format.equals(main.FORMAT_AWS)
            && (main.eucaws_uploads_method.equals(main.UPLOADS_VIA_TURBOWIN))))) {
      // NB also eucaws + 'uploads via turbowin': format101 by default

      // only Windows virus scanners (so not Linux) tend to warn for the compression and
      // decompression programs
      OSDetector.OSType ostype = OSDetector.detect_OS();
      switch (ostype) {
        case WINDOWS:
          FORMAT_101.compression_exe = FORMAT_101.COMPRESSION_EXE_WIN;
          FORMAT_101.decompression_exe = FORMAT_101.DECOMPRESSION_EXE_WIN;

          String info_message =
              "In case you get a warning of your virus scanner: "
                  + "\""
                  + FORMAT_101.compression_exe
                  + "\""
                  + " and "
                  + "\""
                  + FORMAT_101.decompression_exe
                  + "\""
                  + " are essential parts of "
                  + main.APPLICATION_NAME
                  + " required for coding and decoding of format 101";
          JOptionPane.showMessageDialog(
              null, info_message, main.APPLICATION_NAME + " info", JOptionPane.INFORMATION_MESSAGE);
          break;
      } // switch (ostype)
    } // if ( (doorgaan == true) etc.

    //
    /////// write new (obs) configuration settings to file(s)
    //
    if (doorgaan == true) {
      // write meta (station) data to configuration files
      main.schrijf_configuratie_regels();

      /* message */
      String info = "Changes will take full effect after a TurboWin+ restart";
      JOptionPane.showMessageDialog(
          null, info, main.APPLICATION_NAME + " info", JOptionPane.INFORMATION_MESSAGE);

      /* close this obs format settings input page */
      setVisible(false);
      dispose();
    } // if (doorgaan == true)
  } // GEN-LAST:event_OK_button_actionPerformed

