  private void AWS_itemStateChanged(
      java.awt.event.ItemEvent evt) { // GEN-FIRST:event_AWS_itemStateChanged
    // TODO add your handling code here:

    if (jRadioButton7.isSelected() == true) // AWS format
    {
      jRadioButton3.setSelected(false); // uploads via eucaws
      jRadioButton4.setSelected(false); // uploads via turbowin

      jRadioButton3.setEnabled(true); // uploads via eucaws
      jRadioButton4.setEnabled(true); // uploads via turbowin

      jCheckBox1.setSelected(false); // add OBS_ID to SMD input
      jCheckBox1.setEnabled(true); // add OBS_ID to SMD input
    } // if (jRadioButton7.isSelected() == true)
  } // GEN-LAST:event_AWS_itemStateChanged

  private void EUCAWS_uploads_via_turbowin_itemStateChanged(
      java.awt.event.ItemEvent
          evt) { // GEN-FIRST:event_EUCAWS_uploads_via_turbowin_itemStateChanged
    // TODO add your handling code here:

    // obs uploads/sending via TurboWin+ then there is no SMD input (SMD input always via iridium
    // modem of the EUCAWS)

    jCheckBox1.setSelected(false); // add OBS_ID to SMD input
    jCheckBox1.setEnabled(false); // add OBS_ID to SMD input
  } // GEN-LAST:event_EUCAWS_uploads_via_turbowin_itemStateChanged

  private void EUCAWS_uploads_via_AWS_itemStateChanged(
      java.awt.event.ItemEvent evt) { // GEN-FIRST:event_EUCAWS_uploads_via_AWS_itemStateChanged
    // TODO add your handling code here:

    jCheckBox1.setEnabled(true); // add OBS_ID to SMD input
  } // GEN-LAST:event_EUCAWS_uploads_via_AWS_itemStateChanged

  private void initComponents2() {
    // initialisation
    jRadioButton1.setSelected(false); // FM13
    jRadioButton2.setSelected(false); // format 101
    jRadioButton3.setSelected(false); // uploads via eucaws
    jRadioButton4.setSelected(false); // uploads via turbowin
    jRadioButton7.setSelected(false); // AWS
    jCheckBox1.setSelected(false); // add OBS_ID to SMD input

    //
    ////// set (previous) selected values
    //

    // format (FM13 or AWS or format 101)
    if (main.obs_format.equals(main.FORMAT_FM13)) {
      jRadioButton1.setSelected(true);
    } else if (main.obs_format.equals(main.FORMAT_101)) {
      jRadioButton2.setSelected(true);
    } else if (main.obs_format.equals(main.FORMAT_AWS)) {
      jRadioButton7.setSelected(true);

      // EUCAWS uploads method
      if (main.eucaws_uploads_method.equals(main.UPLOADS_VIA_EUCAWS)) {
        jRadioButton3.setSelected(true); // uploads via eucaws
      } else if (main.eucaws_uploads_method.equals(main.UPLOADS_VIA_TURBOWIN)) {
        jRadioButton4.setSelected(true); // uploads via turbowin
      } else // default
      {
        jRadioButton3.setSelected(true); // uploads via eucaws
      }

      // EUCAWS, add OBS_ID to SMD input
      if (main.eucaws_obs_id) // boolean; add OBS_ID to SMD iput
      {
        jCheckBox1.setSelected(true);
      }
    } // else if (main.obs_format.equals(main.FORMAT_AWS))
  }

